// Merge outputs from Agent 1 and Agent 2 into one object
const items = $input.all();

function parseGroqResponse(item) {
  try {
    let text = item.json.choices[0].message.content.trim();
    // Strip markdown fences if present
    if (text.startsWith('```')) {
      text = text.split('```')[1];
      if (text.startsWith('json')) text = text.slice(4);
    }
    return JSON.parse(text.trim());
  } catch(e) {
    console.log('Parse error:', e.message);
    return {};
  }
}

const resumeData = parseGroqResponse(items[0]);
const jdData     = parseGroqResponse(items[1]);

return [{
  json: {
    resume_skills:    resumeData.skills || [],
    resume_keywords:  resumeData.all_keywords || [],
    resume_bullets:   (resumeData.experience_bullets || []).slice(0, 5),
    resume_education: resumeData.education || [],
    resume_format:    resumeData.format_flags || {},
    has_summary:      resumeData.has_summary || false,
    jd_required:      jdData.required_skills || [],
    jd_preferred:     jdData.preferred_skills || [],
    jd_technologies:  jdData.technologies || [],
    jd_keywords:      (jdData.keywords || []).slice(0, 35),
    jd_red_flags:     jdData.red_flags_if_missing || [],
    jd_experience:    jdData.experience_required || '',
    jd_seniority:     jdData.seniority || ''
  }
}];

