// Assemble final API response from agents 3 and 4
function parseGroq(item) {
  try {
    let text = item.json.choices[0].message.content.trim();
    if (text.startsWith('```')) {
      text = text.split('```')[1];
      if (text.startsWith('json')) text = text.slice(4);
    }
    return JSON.parse(text.trim());
  } catch(e) {
    return {};
  }
}

const gap     = parseGroq($('5. Agent 3 — Gap Analyzer').first());
const rewrite = parseGroq($('6. Agent 4 — Rewriter').first());

const score = Math.max(0, Math.min(100, parseInt(gap.overall_score || 0)));

return [{
  json: {
    match_score:       score,
    section_scores:    gap.section_scores || {},
    missing_keywords:  gap.missing_keywords || [],
    present_keywords:  gap.present_keywords || [],
    format_issues:     gap.format_issues || [],
    quick_wins:        gap.quick_wins || [],
    honest_assessment: gap.honest_assessment || '',
    strengths:         gap.strengths || [],
    score_to_75:       gap.score_to_reach_75_percent || [],
    rewritten_bullets: rewrite.suggestions || [],
    summary_suggestion: rewrite.summary || ''
  }
}];
